// Handle login
app.post('/login', (req, res) => {
  const { username, password } = req.body;
  
  if (users.has(username) && users.get(username).password === password) {
    req.session.user = users.get(username);
    res.redirect('/authorize');
  } else {
    res.status(401).send('Invalid credentials');
  }
});

// Authorization endpoint
app.get('/authorize', (req, res) => {
  if (!req.session.user) {
    return res.redirect('/login');
  }

  const { client_id, redirect_uri, response_type, state } = req.query;

  if (!client_id || !redirect_uri || !response_type) {
    return res.status(400).send('Missing required parameters');
  }

  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).send('Invalid client_id');
  }

  if (!client.redirectUris.includes(redirect_uri)) {
    return res.status(400).send('Invalid redirect_uri');
  }

  if (response_type !== 'code') {
    return res.status(400).send('Invalid response_type');
  }

  // Generate authorization code
  const code = crypto.randomBytes(32).toString('hex');
  const codeData = {
    client_id,
    redirect_uri,
    state,
    user_id: req.session.user.id,
    expires_at: Date.now() + 300000 // 5 minutes
  };

  authCodes.set(code, codeData);

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', code);
  if (state) redirectUrl.searchParams.append('state', state);

  res.redirect(redirectUrl.toString());
});

// Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, client_id, client_secret, code, redirect_uri } = req.body;

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  const codeData = authCodes.get(code);
  if (!codeData) {
    return res.status(400).json({ error: 'invalid_grant' });
  }

  if (codeData.expires_at < Date.now()) {
    authCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant' });
  }

  const client = clients.get(client_id);
  if (!client || client.secret !== client_secret) {
    return res.status(400).json({ error: 'invalid_client' });
  }

  if (codeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant' });
  }

  // Generate access token
  const accessToken = crypto.randomBytes(32).toString('hex');
  const tokenData = {
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    client_id,
    user_id: codeData.user_id,
    created_at: Date.now()
  };

  accessTokens.set(accessToken, tokenData);
  authCodes.delete(code);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600
  });
});

// Middleware to validate access tokens
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'access_denied' });
  }

  const tokenData = accessTokens.get(token);
  if (!tokenData || tokenData.created_at + (tokenData.expires_in * 1000) < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token' });
  }

  req.user = { id: tokenData.user_id };
  next();
};

